def binpow(base, exp):
    result = 1
    while exp > 0:
        if exp % 2 == 1:
            result = result * base
        base = base * base
        exp //= 2
    return result


def countIsolated(n, edges):
    if not edges:
        return n
    has_edge = set()
    for u, v in edges:
        has_edge.add(u)
        has_edge.add(v)
    return n - len(has_edge)


def countComponents(n, edges):
    if n == 0:
        return 0

    adj = [[] for _ in range(n + 1)]
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    visited = [False] * (n + 1)
    count = 0

    def dfs(u):
        visited[u] = True
        for v in adj[u]:
            if not visited[v]:
                dfs(v)

    for i in range(1, n + 1):
        if not visited[i]:
            count += 1
            dfs(i)

    return count


